// Throwaway repro harness for F2a — determine the SDK resume failure mode.
import { query } from '@anthropic-ai/claude-agent-sdk';
import {
  mkdtempSync, readdirSync, readFileSync, writeFileSync, cpSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const key = process.env.ANTHROPIC_API_KEY;
if (!key) throw new Error('no ANTHROPIC_API_KEY');

function jsonlPath(home, cwd) {
  const projects = join(home, '.claude', 'projects');
  for (const slug of readdirSync(projects)) {
    for (const f of readdirSync(join(projects, slug))) {
      if (f.endsWith('.jsonl')) return join(projects, slug, f);
    }
  }
  throw new Error('no jsonl found');
}

async function runTurn({ home, cwd, prompt, resume }) {
  let sessionId = resume;
  let resultSubtype, isError, errText;
  try {
    const iter = query({
      prompt,
      options: {
        cwd,
        env: { ...process.env, HOME: home, ANTHROPIC_API_KEY: key },
        permissionMode: 'bypassPermissions',
        ...(resume ? { resume } : {}),
      },
    });
    for await (const msg of iter) {
      if (msg.type === 'system' && msg.subtype === 'init') sessionId = msg.session_id;
      if (msg.type === 'result') {
        resultSubtype = msg.subtype;
        isError = msg.is_error;
        if (msg.subtype !== 'success') errText = JSON.stringify(msg).slice(0, 400);
      }
    }
    return { ok: true, sessionId, resultSubtype, isError, errText };
  } catch (err) {
    return { ok: false, sessionId, errName: err?.name, errMsg: String(err?.message ?? err).slice(0, 500), errStack: (err?.stack ?? '').slice(0, 800) };
  }
}

// 1. Generate a real tool-using turn (Bash echo) → tool_use + tool_result in jsonl.
const home = mkdtempSync(join(tmpdir(), 'repro-home-'));
const cwd = mkdtempSync(join(tmpdir(), 'repro-cwd-'));
const gen = await runTurn({ home, cwd, prompt: 'Run the bash command: echo hello-from-tool. Then tell me the output.' });
console.error('GEN:', JSON.stringify(gen));
const sid = gen.sessionId;
const jp = jsonlPath(home, cwd);
const lines = readFileSync(jp, 'utf-8').split('\n').filter((l) => l.trim().length > 0);
console.error('=== generated', lines.length, 'lines ===');
lines.forEach((l, i) => {
  const o = JSON.parse(l);
  const blocks = Array.isArray(o.message?.content) ? o.message.content.map((b) => b.type + (b.type === 'tool_use' ? `(${b.id})` : b.type === 'tool_result' ? `(${b.tool_use_id})` : '')).join(',') : '';
  console.error(i, o.type, o.message?.role ?? '', blocks);
});

// helper: clone home into a fresh dir, rewrite jsonl with given lines, return new home
function cloneWith(newLinesText) {
  const h2 = mkdtempSync(join(tmpdir(), 'repro-home2-'));
  cpSync(home, h2, { recursive: true });
  // find jsonl in clone
  const jp2 = jsonlPath(h2, cwd);
  writeFileSync(jp2, newLinesText);
  return h2;
}

const fullText = readFileSync(jp, 'utf-8');

// CONTROL: resume the clean transcript with a new prompt.
const control = await runTurn({ home: cloneWith(fullText), cwd, prompt: 'Now say the word: done.', resume: sid });
console.error('\nCONTROL (clean resume):', JSON.stringify(control));

// VARIANT A: truncated final line (last line chopped to half its length) — simulates SIGKILL mid-write.
const half = fullText.slice(0, fullText.length - Math.floor(lines[lines.length - 1].length / 2));
const varA = await runTurn({ home: cloneWith(half), cwd, prompt: 'Now say the word: done.', resume: sid });
console.error('\nVARIANT A (truncated final line):', JSON.stringify(varA));

// VARIANT B: dangling tool_use — drop everything from the first tool_result line onward,
// so the transcript ends with an assistant tool_use that has no matching tool_result.
const toolUseIdx = lines.findIndex((l) => { const o = JSON.parse(l); return Array.isArray(o.message?.content) && o.message.content.some((b) => b.type === 'tool_use'); });
let varB = { skipped: 'no tool_use line found' };
if (toolUseIdx >= 0) {
  const truncated = lines.slice(0, toolUseIdx + 1).join('\n') + '\n';
  varB = await runTurn({ home: cloneWith(truncated), cwd, prompt: 'Now say the word: done.', resume: sid });
}
console.error('\nVARIANT B (dangling tool_use):', JSON.stringify(varB));

