// Repro batch 2 — missing/empty/partial-before-first-message transcript on resume.
import { query } from '@anthropic-ai/claude-agent-sdk';
import {
  mkdtempSync, readdirSync, readFileSync, writeFileSync, cpSync, rmSync,
} from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const key = process.env.ANTHROPIC_API_KEY;
if (!key) throw new Error('no ANTHROPIC_API_KEY');

function jsonlPath(home, cwd) {
  const projects = join(home, '.claude', 'projects');
  for (const slug of readdirSync(projects)) {
    for (const f of readdirSync(join(projects, slug))) {
      if (f.endsWith('.jsonl')) return join(projects, slug, f);
    }
  }
  return null;
}

async function runTurn({ home, cwd, prompt, resume }) {
  let sessionId = resume;
  try {
    const iter = query({
      prompt,
      options: {
        cwd,
        env: { ...process.env, HOME: home, ANTHROPIC_API_KEY: key },
        permissionMode: 'bypassPermissions',
        ...(resume ? { resume } : {}),
      },
    });
    let resultSubtype, isError;
    for await (const msg of iter) {
      if (msg.type === 'system' && msg.subtype === 'init') sessionId = msg.session_id;
      if (msg.type === 'result') { resultSubtype = msg.subtype; isError = msg.is_error; }
    }
    return { ok: true, sessionId, resultSubtype, isError };
  } catch (err) {
    return { ok: false, sessionId, errName: err?.name, errMsg: String(err?.message ?? err).slice(0, 600) };
  }
}

// generate a clean no-tool turn to get a real sessionId + jsonl
const home = mkdtempSync(join(tmpdir(), 'r2-home-'));
const cwd = mkdtempSync(join(tmpdir(), 'r2-cwd-'));
const gen = await runTurn({ home, cwd, prompt: 'Say: ready.' });
const sid = gen.sessionId;
const jp = jsonlPath(home, cwd);
const fullText = readFileSync(jp, 'utf-8');
const lines = fullText.split('\n').filter((l) => l.trim().length > 0);
console.error('GEN sid=', sid, 'lines=', lines.length);

function cloneThen(mutate) {
  const h2 = mkdtempSync(join(tmpdir(), 'r2-clone-'));
  cpSync(home, h2, { recursive: true });
  const jp2 = jsonlPath(h2, cwd);
  mutate(jp2, h2);
  return h2;
}

// C: jsonl deleted entirely (resume a sessionId with no transcript file)
const c = await runTurn({ home: cloneThen((p) => rmSync(p)), cwd, prompt: 'Say: done.', resume: sid });
console.error('\nC (jsonl deleted):', JSON.stringify(c));

// D: empty jsonl
const d = await runTurn({ home: cloneThen((p) => writeFileSync(p, '')), cwd, prompt: 'Say: done.', resume: sid });
console.error('\nD (empty jsonl):', JSON.stringify(d));

